// ── Config ─────────────────────────────────────────────────
// Set MONO_SECRET_KEY in n8n environment variables
// Set B3EQ_ACCOUNT_IDS as comma-separated Mono account IDs
// e.g. B3EQ_ACCOUNT_IDS=63b1a2c3d4e5f6a7b8c9d0e1,63b2a3c4d5e6f7a8b9c0d1e2

const secretKey  = $env.MONO_SECRET_KEY;
const accountIds = ($env.B3EQ_ACCOUNT_IDS || '').split(',').map(s => s.trim()).filter(Boolean);
const yesterday  = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateFrom   = yesterday.toISOString().split('T')[0];
const dateTo     = new Date().toISOString().split('T')[0];

if (!secretKey)    throw new Error('MONO_SECRET_KEY not set in n8n environment');
if (!accountIds.length) throw new Error('B3EQ_ACCOUNT_IDS not set — comma-separated Mono account IDs');

return accountIds.map(id => ({ json: { account_id: id, date_from: dateFrom, date_to: dateTo, secret_key: secretKey } }));

// ── Parse & normalise bank transactions ─────────────────────
// Maps Mono transaction format to b3Ɛq ledger staging format

const items = $input.all();
const results = [];
let total_debit = 0;
let total_credit = 0;

for (const item of items) {
  const data = item.json;
  const txns = data.data || data.transactions || [];
  const account_id = item.json.meta?.account_id || 'unknown';

  for (const txn of txns) {
    const amount    = Math.abs(parseFloat(txn.amount || 0)) / 100; // Mono returns kobo
    const is_debit  = txn.type === 'debit'  || (txn.amount && txn.amount < 0);
    const is_credit = txn.type === 'credit' || (txn.amount && txn.amount > 0);

    // Auto-suggest ledger account based on narration
    const narration = (txn.narration || txn.description || '').toLowerCase();
    let suggested_account = '1002'; // Default: bank account
    let suggested_journal = 'JV-BK';

    if (narration.includes('salary') || narration.includes('payroll'))  { suggested_account = '6000'; suggested_journal = 'JV-PY'; }
    else if (narration.includes('rent') || narration.includes('lease')) { suggested_account = '6010'; suggested_journal = 'JV-BK'; }
    else if (narration.includes('vat') || narration.includes('firs'))   { suggested_account = '2100'; suggested_journal = 'JV-TX'; }
    else if (narration.includes('paye') || narration.includes('tax'))   { suggested_account = '2120'; suggested_journal = 'JV-TX'; }
    else if (narration.includes('transfer in') || narration.includes('trf cr')) { suggested_account = '1002'; }
    else if (narration.includes('fuel') || narration.includes('petrol')) { suggested_account = '6014'; }
    else if (narration.includes('internet') || narration.includes('mtn') || narration.includes('airtel')) { suggested_account = '6012'; }

    if (is_debit)  total_debit  += amount;
    if (is_credit) total_credit += amount;

    results.push({ json: {
      source:            'mono',
      account_id,
      txn_id:            txn.id || txn._id,
      date:              txn.date?.split('T')[0] || new Date().toISOString().split('T')[0],
      narration:         txn.narration || txn.description || '',
      amount,
      type:              is_debit ? 'DEBIT' : 'CREDIT',
      balance:           parseFloat(txn.balance || 0) / 100,
      suggested_account,
      suggested_journal,
      status:            'STAGED',
      requires_review:   suggested_account === '1002' && amount > 100000
    }});
  }
}

if (results.length === 0) {
  return [{ json: { message: 'No transactions found for period', total_debit: 0, total_credit: 0 } }];
}

console.log(`Parsed ${results.length} transactions. Debits: ₦${total_debit.toLocaleString()} | Credits: ₦${total_credit.toLocaleString()}`);
return results;

const items = $input.all();
const review_items = items.filter(i => i.json.requires_review);
const normal_items = items.filter(i => !i.json.requires_review);
const total = items.length;
const review_count = review_items.length;

const review_lines = review_items.slice(0, 5).map(i =>
  `  • ${i.json.date} | ${i.json.type} | ₦${i.json.amount.toLocaleString()} | ${i.json.narration.slice(0,40)}`
);

const lines = [
  `🏦 *b3Ɛq Bank Feed Sync — ${new Date().toLocaleDateString('en-NG')}*`,
  ``,
  `✓ ${total} transactions imported from Mono`,
  `  Categorised: ${total - review_count}`,
  `  Needs review: ${review_count}`,
  ``,
  total > 0 ? `→ Review in Dolibarr: Financial → Bank/Cash Accounts` : '',
  review_count > 0 ? `\n⚠ High-value unmatched transactions:` : '',
  ...review_lines,
  review_count > 5 ? `  ... and ${review_count - 5} more` : ''
].filter(l => l !== undefined);

return [{ json: { summary: lines.join('\n'), total, review_count } }];
